-- Formulário de Elevadores: Fornecedor (cadastro expansível), Vendedor,
-- Nº de Cotação sequencial + histórico real da planilha de controle de
-- cotações (Braz_Controle_Cotação_Equipamentos.xlsx). Ver issues #76/#77/#78.

-- 1) Fornecedores — cadastro expansível (não hardcode no front)
create table if not exists public.fornecedores_elevador (
  id uuid primary key default gen_random_uuid(),
  nome text not null unique,
  ativo boolean not null default true,
  created_at timestamptz not null default now()
);
insert into public.fornecedores_elevador (nome) values ('Glarie'), ('BST'), ('Seelon')
  on conflict (nome) do nothing;

alter table public.fornecedores_elevador enable row level security;
drop policy if exists fornecedores_elevador_all_anon on public.fornecedores_elevador;
create policy fornecedores_elevador_all_anon on public.fornecedores_elevador
  for all to anon using (true) with check (true);
drop policy if exists fornecedores_elevador_all_auth on public.fornecedores_elevador;
create policy fornecedores_elevador_all_auth on public.fornecedores_elevador
  for all to authenticated using (true) with check (true);

-- 2) Fornecedor por unidade (elevador) + Vendedor no header
alter table public.formularios_elevador_unidades
  add column if not exists fornecedor text;

alter table public.formularios_elevador
  add column if not exists vendedor text;

-- 3) Nº de cotação sequencial — continua a numeração real da planilha
-- histórica (maior N°Cotação real = 897, ver homologação na issue #76).
create sequence if not exists public.formulario_elevador_numero_cotacao_seq start 898;

alter table public.formularios_elevador
  add column if not exists numero_cotacao integer not null
    default nextval('public.formulario_elevador_numero_cotacao_seq');

-- 4) Histórico bruto da planilha de controle de cotações (pré-sistema).
-- Ingestão fiel — sem normalizar inconsistências de digitação (CNPJs
-- incompletos, datas malformadas, 1 valor de coluna deslocado, etc; ver
-- relatório de homologação na issue #76). Por isso as colunas de texto
-- (inclusive datas) ficam como `text`, não `date` — a planilha tem valores
-- como "31/072024" e "DECLINADO" numa coluna de data.
create table if not exists public.cotacoes_elevador_historico (
  id uuid primary key default gen_random_uuid(),
  numero_cotacao integer not null,
  data text,
  data_dev_vendedor text,
  numero_omie text,
  vendedor text,
  origem_venda text,
  cnpj_comprador text,
  nome_cliente text,
  endereco text,
  nome_instalacao text,
  endereco_instalacao text,
  estado_instalacao text,
  descricao_equipamento text,
  nome_contato text,
  telefone_contato text,
  email_contato text,
  status text,
  motivo text,
  conquistado text,
  valor_conquistado text,
  created_at timestamptz not null default now()
);
create index if not exists cotacoes_elevador_historico_numero_cotacao_idx
  on public.cotacoes_elevador_historico (numero_cotacao);

alter table public.cotacoes_elevador_historico enable row level security;
drop policy if exists cotacoes_elevador_historico_all_anon on public.cotacoes_elevador_historico;
create policy cotacoes_elevador_historico_all_anon on public.cotacoes_elevador_historico
  for all to anon using (true) with check (true);
drop policy if exists cotacoes_elevador_historico_all_auth on public.cotacoes_elevador_historico;
create policy cotacoes_elevador_historico_all_auth on public.cotacoes_elevador_historico
  for all to authenticated using (true) with check (true);

-- 5) Ingestão dos 894 registros reais da planilha (linhas com cliente
-- preenchido; as ~197 linhas "reservadas" sem dado real foram descartadas).
delete from public.cotacoes_elevador_historico;

